    st.markdown("""
    <script>
    (function() {
      function enforceOneAudio() {
        document.querySelectorAll('audio').forEach(function(audio) {
          audio.removeEventListener('play', audio._rbmHandler || function(){});
          audio._rbmHandler = function() {
            document.querySelectorAll('audio').forEach(function(other) {
              if (other !== audio) { other.pause(); other.currentTime = 0; }
            });
          };
          audio.addEventListener('play', audio._rbmHandler);
        });
      }
      // Run now and observe DOM changes
      enforceOneAudio();
      var obs = new MutationObserver(enforceOneAudio);
      obs.observe(document.body, {childList: true, subtree: true});
    })();
    </script>
    """, unsafe_allow_html=True)

