    if not st.session_state.admin_logged:
        pwd = st.text_input("Mot de passe", type="password", placeholder="Entrez le mot de passe admin")
        if st.button("🔓 Se connecter", use_container_width=True):
            if pwd == ADMIN_PASSWORD:
                st.session_state.admin_logged = True; st.rerun()
            else:
                st.error("❌ Mot de passe incorrect")
    else:
        st.success("✅ Connecté en tant qu'administrateur")

        st.subheader("📤 Publier une nouvelle annonce")
        with st.form("upload_form", clear_on_submit=True):
            c1, c2 = st.columns(2)
            with c1:
                ann_date = st.date_input("📅 Date", datetime.today())
            with c2:
                ann_lang = st.selectbox("🌍 Langue", options=list(LANGUAGES.keys()),
                                        format_func=lambda x: f"{LANGUAGES[x]['emoji']} {x}")
            ann_desc = st.text_area("📝 Description (optionnel)", height=70,
                                    placeholder="Ex: Bulletin météo semaine 12...")
            audio_file = st.file_uploader("🎵 Fichier audio (MP3, OGG, WAV, M4A)",
                                           type=["mp3","ogg","wav","m4a"])
            submitted = st.form_submit_button("✅ Publier", use_container_width=True)
            if submitted:
                if not audio_file:
                    st.error("Veuillez sélectionner un fichier audio.")
                else:
                    date_str = ann_date.strftime("%Y-%m-%d")
                    safe_lang = ann_lang.replace(" ","_").lower()
                    fname = f"{date_str}_{safe_lang}_{audio_file.name}"
                    spath = os.path.join(AUDIO_DIR, fname)
                    with open(spath, "wb") as f:
                        f.write(audio_file.read())
                    announcements.append({
                        "id": f"{date_str}_{safe_lang}",
                        "date": date_str,
                        "language": ann_lang,
                        "description": ann_desc,
                        "audio_path": spath,
                        "created_at": datetime.now().isoformat()
                    })
                    save_announcements(announcements)
                    st.success(f"✅ Annonce du {date_str} en {ann_lang} publiée !")
                    st.rerun()

        st.markdown("---")
        st.subheader("📋 Annonces existantes")
        if not announcements:
            st.info("Aucune annonce publiée.")
        else:
            for i, ann in enumerate(sorted(announcements, key=lambda x: x["date"], reverse=True)):
                lm = LANGUAGES.get(ann["language"], {"color":"#333","emoji":"🔵"})
                col1, col2 = st.columns([5, 1])
                with col1:
                    st.markdown(f"**{lm['emoji']} {ann['date']}** — {ann['language']}")
